#include <stdio.h>
#include <stdlib.h>
int main(){
    int T; if(scanf("%d",&T)!=1) return 0;
    while(T--){
        int N; scanf("%d",&N);
        long long *a = (long long*)malloc(N*sizeof(long long));
        for(int i=0;i<N;i++) scanf("%lld",&a[i]);
        for(int i=0;i<N;i++){
            long long best = 0;
            if(i>0) best = a[i] & a[i-1];
            if(i+1<N){
                long long v = a[i] & a[i+1];
                if(v>best) best = v;
            }
            printf("%lld",best);
            if(i+1<N) printf(" ");
        }
        printf("\n");
        free(a);
    }
    return 0;
}

