import sys

def solve():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    it = iter(data)
    t = int(next(it))
    out_lines = []
    for _ in range(t):
        n = int(next(it))
        a = [int(next(it)) for _ in range(n)]
        res = []
        for i in range(n):
            best = 0
            if i > 0:
                best = a[i] & a[i-1]
            if i + 1 < n:
                v = a[i] & a[i+1]
                if v > best:
                    best = v
            res.append(str(best))
        out_lines.append(' '.join(res))
    sys.stdout.write('\n'.join(out_lines))

if __name__ == "__main__":
    solve()

